function: () => {
  const s = document.getElementById('agents-home-status');
  const tabs = document.querySelectorAll('#nav-agents .agent-tab').length;
  return { statusHTML: s ? s.innerHTML : '(none)', agentTabCount: tabs };
}

function: () => {
  const main = document.getElementById('btn-server-mgmt');
  const tabs = [...document.querySelectorAll('#nav-servers [data-server-key]')].map(t => ({
    name: t.dataset.serverName,
    cls: [...t.classList].filter(c => c.startsWith('server-')).join(',') || '(none)'
  }));
  return { mainTabClasses: [...main.classList].filter(c => c.startsWith('server-')).join(',') || '(none)', tabs };
}

function: () => {
  const st = document.getElementById('srv-status');
  const stText = document.getElementById('srv-status-text');
  const rows = document.querySelectorAll('#servers-detail-body .msi-entry').length;
  return {
    statusClass: st ? st.className : '(none)',
    statusText: stText ? stText.textContent.slice(0,80) : '(none)',
    logRowCount: rows,
    hasFilter: !!document.getElementById('srv-filter'),
  };
}

function: () => {
  const f = document.getElementById('srv-filter');
  f.value = 'GET /api';
  f.dispatchEvent(new Event('input'));
  const all = [...document.querySelectorAll('#servers-detail-body .msi-entry')];
  const visible = all.filter(el => el.style.display !== 'none').length;
  const hidden = all.filter(el => el.style.display === 'none').length;
  return { total: all.length, visible, hidden };
}

