function: () => {
  const tabs = [...document.querySelectorAll('#nav-rol-finance-reports [data-report-key]')].map(t => ({
    label: t.textContent, key: t.dataset.reportKey, cls: t.className
  }));
  const views = [...document.querySelectorAll('#rol-finance-reports-views section')].map(v => ({ id: v.id, active: v.classList.contains('active'), hasIframe: !!v.querySelector('iframe') }));
  return { tabCount: tabs.length, tabs: tabs.slice(0,4), views: views.slice(0,4) };
}

function: async () => {
  const iframe = document.querySelector('#rol-finance-report-amex-61006 iframe');
  if (!iframe) return { err: 'no iframe' };
  // Wait for the iframe to finish loading if needed.
  if (iframe.contentDocument && iframe.contentDocument.readyState !== 'complete') {
    await new Promise(r => iframe.addEventListener('load', r, { once: true }));
  }
  const d = iframe.contentDocument;
  if (!d) return { err: 'no contentDocument (cross-origin?)' };
  const vt = d.getElementById('verified-transactions');
  const keep = vt ? vt.closest('section') : null;
  const sections = [...d.querySelectorAll('body section, body > * section')];
  const parent = keep ? keep.parentElement : null;
  const siblingSections = parent ? [...parent.children].filter(c => c.tagName === 'SECTION') : [];
  return {
    hasVerified: !!vt,
    keptVisible: keep ? keep.style.display !== 'none' : null,
    siblingCount: siblingSections.length,
    hiddenSiblings: siblingSections.filter(s => s.style.display === 'none').length,
  };
}

function: async () => {
  // Give the immediate poll a tick.
  await new Promise(r => setTimeout(r, 500));
  const tab = document.getElementById('btn-agents-home');
  const modal = document.getElementById('code-change-modal');
  let codeStatus;
  try { codeStatus = await fetch('/api/code-status').then(r => r.json()); } catch (e) { codeStatus = { err: e.message }; }
  return {
    tabBlinking: tab ? tab.classList.contains('tab-alert') : null,
    modalHidden: modal ? modal.classList.contains('hidden') : null,
    codeStatus,
  };
}

function: () => {
  const title = document.getElementById('agent-detail-title');
  const activeTab = document.querySelector('#nav-agent-detail .tab.active');
  const activeView = document.querySelector('.view.active');
  return {
    title: title ? title.textContent : null,
    activeDetailTab: activeTab ? activeTab.textContent : null,
    activeViewId: activeView ? activeView.id : null,
  };
}

function: () => {
  const mainNavVisible = !document.getElementById('nav-main').classList.contains('hidden');
  const homeActive = document.getElementById('home') && document.getElementById('home').classList.contains('active');
  const fullbleed = document.getElementById('main-content').classList.contains('fullbleed');
  return { mainNavVisible, homeActive, fullbleed };
}
